var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"저희 사람들이 출항 준비를 하는 동안, 여러분들은 편히 쉬고 계시면 돼요.","JPN":"こちらで出航準備をしている間、皆さんは少し休んでいてください。","ENG":"Why don't you rest while our staff gets the ship ready for departure?","TWN":"在我們做出航準備的這段時間，請各位先休息一下。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"전 마실 것들을 좀 가져오겠습니다.","JPN":"私はお飲み物を準備しましょう。","ENG":"I'll bring you some refreshments.","TWN":"我去拿點喝的過來。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"아, 배려 감사합니다.","JPN":"あっ、お気遣いいただきありがとうございます。","ENG":"Oh, thank you.","TWN":"好的，非常感謝。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어라? 카린 양은 언제 수영복으로 갈아입으셨어요?","JPN":"うん？　カリンさん、いつ水着に着替えたんですか？","ENG":"Err? Karin, when did you change into a swimsuit?","TWN":"咦？卡琳小姐什麼時候換上泳裝了？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"평소의 카린 양이라면 임무 도중에 노는 게 말이 되냐며 화낼 줄 알았는데.","JPN":"いつものカリンさんなら、任務中に遊ぶなんてお説教ものですよね？","ENG":"I thought the Karin I know would never agree to have fun while on a mission.","TWN":"如果是平時的卡琳小姐，一定會大發雷霆，說我在執行任務時偷懶的。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"저, 저라고 항상 일 밖에 모르는 줄 알아요?","JPN":"わ、私だっていつも仕事のことばかり考えてるわけじゃありません。","ENG":"E-even I know how to have fun, you know.","TWN":"妳、妳以為我只知道工作嗎！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"물론 시기적으로는 지금 임무를 수행 중이긴 하지만......","JPN":"もちろん、今は任務の最中ではありますが……","ENG":"It's true that we're currently on a mission,","TWN":"雖然現在確實是在執行任務的期間……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"따지고 보면 저흰 조난을 당한 상황이고, 자력으로 돌아갈 방법도 없는데다가......","JPN":"よく考えてみれば私たちは遭難している状況で、自力で帰る方法もありませんし……","ENG":"but we've been stranded and are unable to go back on our own.","TWN":"但我們現在被困在這裡，也找不到回去的辦法……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"수영을 하려면 당연히 수영복을 입어야 하는 거고......","JPN":"水泳をするなら当然水着に着替えるべきかと……","ENG":"Also, I have to wear a swimsuit to swim.","TWN":"而且游泳當然要穿泳裝……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"그, 그리고 무엇보다 시영 씨도 항상 즐길 수 있을 때 즐기라고 나한테 그랬잖아요!","JPN":"そ、それに何よりシノンさんも遊べる時は遊べと、いつも言ってるではありませんか！","ENG":"M-moreover, you told me to have fun while I can!","TWN":"還、還有，時雨小姐不是常說該享受的時候就要盡情享受嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그럼요! 지당하신 말씀이죠!","JPN":"はい、おっしゃるとおりです！","ENG":"Absolutely! That's exactly what I told you.","TWN":"就是啊！妳說得對！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"카린 양이 점점 더 자기 합리화...... 아니 상황에 유연하게 대처하는 모습을 보니 참 기분이 좋네요, 하하하.","JPN":"カリンさんが自分の行動を合理化……いや、状況に合わせて柔軟に対処する姿が見れて嬉しいです、ハハハ。","ENG":"I'm glad to see you trying to justify—I mean, adapt to your situation. Hah hah.","TWN":"看到卡琳小姐越來越合理化自己的行為……不，遊刃有餘地應付危機的樣子，真讓人高興哪，哈哈哈。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"크윽......","JPN":"くっ……","ENG":"Hmpf!","TWN":"唔……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으으으음~ 개운해!","JPN":"う～ん、スッキリ！","ENG":"Mm, mm! I feel so refreshed!","TWN":"唔啊啊啊～好舒服！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"앗, 깨어났다.","JPN":"あっ、起きた。","ENG":"Ah, she's up!","TWN":"啊，醒了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"응? 주위에 모르는 사람들이 잔뜩 있어.","JPN":"うん？　知らない人たちばっかり。","ENG":"Mm? Why am I surrounded by strangers?","TWN":"嗯？為什麼旁邊會有這麼多陌生人。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"다행히 성격은 원래대로 돌아온 것 같군요.","JPN":"幸い、性格は元に戻ったようですね。","ENG":"Thank God, she's back to being herself.","TWN":"幸好她恢復成原本的人格了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어째서 트윈즈라는 이름을 달고 있는지 이젠 알 거 같네요.","JPN":"なぜ名前にツインズがついてるか、わかるような気がします。","ENG":"Her surname, Twins, totally matches her personality.","TWN":"我好像知道她為什麼會叫“雙子”了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};